import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // aspectRatio is not supported; warn the caller
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size setting to control dimensions.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    // Provider-level size setting overrides the standard size parameter
    const resolvedSize = pixelartOptions?.size ?? size;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    const { value: responseData, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combinedHeaders,
      body: {
        model: this.modelId,
        prompt,
        n: n ?? 1,
        size: resolvedSize,
        style: pixelartOptions?.style,
        pixel_density: pixelartOptions?.pixelDensity,
        seed,
      },
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartGenerateResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: responseData.images,
      warnings,
      providerMetadata: {
        pixelart: {
          generationId: responseData.generation_id ?? undefined,
        },
      },
      response: {
        modelId: responseData.model ?? this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Provider options schema (passed via providerOptions.pixelart)
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The size of the generated image (e.g., "512x512", "1024x1024").
       * Takes precedence over the standard `size` parameter.
       */
      size: z.string().optional(),

      /**
       * The artistic style for the pixel art output.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * The pixel density (dots per inch) for the generated image.
       */
      pixelDensity: z.number().positive().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = {
  size?: string;
  style?: 'pixel' | 'retro' | '8bit';
  pixelDensity?: number;
};

// Response schema for a successful image generation call
const pixelartGenerateResponseSchema = z.object({
  images: z.array(z.string()),
  model: z.string().nullish(),
  generation_id: z.string().nullish(),
});

// Error response schema
const pixelartErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
  message: z.string().optional(),
});

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorSchema,
  errorToMessage: error => {
    const parsed = pixelartErrorSchema.safeParse(error);
    if (!parsed.success) return 'Unknown PixelArt error';
    const { error: errObj, message } = parsed.data;
    return errObj?.message ?? message ?? 'Unknown PixelArt error';
  },
});

