55	  options: PixelArtProviderSettings = {},
56	): PixelArtProvider {
57	  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
58	
59	  const getHeaders = () =>
60	    withUserAgentSuffix(
